mapper.select:
select sd.dept_id, sd.name, sd.parent_id, sd.create_time, sd.merchant_id, sd.dept_number, sd2.name as parentName from sys_dept sd left join sys_dept sd2 on sd.parent_id = sd2.dept_id where sd.del_flag = '0'
and sd.merchant_id = #{vo.merchantId}
and sd.name like concat('%', #{vo.name}, '%')
